const body = $input.first().json.body || $input.first().json;

let source = '';
let message_text = '';
let sender_phone = '';
let sender_name = '';
let sender_instagram_user_id = '';

// Detect WhatsApp
if (body.entry && body.entry[0] && body.entry[0].changes &&
    body.entry[0].changes[0] && body.entry[0].changes[0].value &&
    body.entry[0].changes[0].value.messages &&
    body.entry[0].changes[0].value.messages.length > 0) {

  source = 'whatsapp';
  const msg = body.entry[0].changes[0].value.messages[0];
  message_text = (msg.type === 'text' && msg.text) ? msg.text.body : '[non-text message]';
  sender_phone = msg.from || '';
  const contacts = body.entry[0].changes[0].value.contacts;
  sender_name = (contacts && contacts[0] && contacts[0].profile) ? contacts[0].profile.name : '';

// Detect Instagram DM
} else if (body.entry && body.entry[0] && body.entry[0].messaging &&
           body.entry[0].messaging.length > 0) {

  source = 'instagram_dm';
  const messaging = body.entry[0].messaging[0];
  sender_instagram_user_id = messaging.sender ? messaging.sender.id : '';
  message_text = (messaging.message && messaging.message.text) ? messaging.message.text : '[non-text message]';
  sender_name = 'Instagram User';

} else {
  // Neither — likely a delivery/read receipt, ignore
  source = 'ignore';
}

return [{
  json: {
    source,
    message_text,
    sender_phone,
    sender_name,
    sender_instagram_user_id,
    _isValid: (source === 'whatsapp' || source === 'instagram_dm')
  }
}];

const item = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

// Look up existing lead
let existingLead = null;
let botReplyCount = 0;

try {
  let lookupUrl;
  if (item.source === 'whatsapp') {
    lookupUrl = CRM + '/api/leads?phone=' + encodeURIComponent(item.sender_phone);
  } else {
    lookupUrl = CRM + '/api/leads?instagram_user_id=' + encodeURIComponent(item.sender_instagram_user_id);
  }

  const leadResp = await this.helpers.httpRequest({
    method: 'GET',
    url: lookupUrl,
    headers: headers,
    json: true
  });

  if (leadResp.data) {
    existingLead = Array.isArray(leadResp.data) ? leadResp.data[0] : leadResp.data;
    botReplyCount = existingLead ? (parseInt(existingLead.bot_reply_count) || 0) : 0;
  }
} catch(e) {}

const needsEscalation = botReplyCount >= 3;

return [{
  json: {
    ...item,
    existing_lead: existingLead,
    bot_reply_count: botReplyCount,
    existing_lead_score: existingLead ? existingLead.lead_score : null,
    _needsEscalation: needsEscalation
  }
}];

const item = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

const escalationReply = 'Thank you for your patience! Our counselor will assist you shortly. 😊';

// Send escalation reply
if (item.source === 'whatsapp') {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://graph.facebook.com/v19.0/' + $env.WHATSAPP_PHONE_NUMBER_ID + '/messages',
    headers: { 'Authorization': 'Bearer ' + $env.WHATSAPP_ACCESS_TOKEN, 'Content-Type': 'application/json' },
    body: {
      messaging_product: 'whatsapp',
      to: item.sender_phone,
      type: 'text',
      text: { body: escalationReply }
    },
    json: true
  });
} else {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://graph.facebook.com/v19.0/me/messages',
    headers: { 'Authorization': 'Bearer ' + $vars.META_ACCESS_TOKEN, 'Content-Type': 'application/json' },
    body: {
      recipient: { id: item.sender_instagram_user_id },
      message: { text: escalationReply }
    },
    json: true
  });
}

// Urgent Telegram alert
const contactInfo = item.source === 'whatsapp' ? 'Phone: ' + item.sender_phone : 'IG ID: ' + item.sender_instagram_user_id;
await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
  body: {
    chat_id: $env.TELEGRAM_CHAT_ID,
    text: '🚨 ESCALATION: ' + item.sender_name + ' has received 3+ bot replies. Manual follow-up needed NOW.\n' + contactInfo + '\nSource: ' + item.source + '\nLast message: ' + item.message_text
  },
  json: true
});

// Update lead status to escalated
await this.helpers.httpRequest({
  method: 'POST',
  url: CRM + '/api/leads',
  body: {
    phone: item.sender_phone || undefined,
    instagram_user_id: item.sender_instagram_user_id || undefined,
    follow_up_status: 'escalated'
  },
  headers: headers,
  json: true
});

return [{ json: { status: 'escalated', sender: item.sender_name } }];

const item = $input.first().json;
const text = (item.message_text || '').toLowerCase();

// Intent detection via keyword matching
let intent = 'general_enquiry';
let sla_time = 'within 24 hours';

const feesKeywords = ['fee', 'fees', 'price', 'cost', 'charges', 'kitna', 'paisa', 'rupee', 'rupees'];
const courseKeywords = ['course', 'learn', 'learning', 'training', 'class', 'enroll', 'join', 'admission', 'batch'];
const locationKeywords = ['where', 'location', 'address', 'kahan', 'place', 'office', 'center', 'centre'];
const timingKeywords = ['time', 'timing', 'batch', 'schedule', 'kab', 'when', 'start', 'morning', 'evening'];

if (feesKeywords.some(kw => text.includes(kw))) {
  intent = 'fees_question';
  sla_time = 'within 1 hour';
} else if (courseKeywords.some(kw => text.includes(kw))) {
  intent = 'course_enquiry';
  sla_time = 'within 4 hours';
} else if (locationKeywords.some(kw => text.includes(kw))) {
  intent = 'location_enquiry';
  sla_time = 'within 4 hours';
} else if (timingKeywords.some(kw => text.includes(kw))) {
  intent = 'batch_timing';
  sla_time = 'within 4 hours';
}

// Lead scoring — never downgrade
let lead_score = 'Cold';
if (intent === 'fees_question') {
  lead_score = 'Hot';
} else if (['course_enquiry', 'location_enquiry', 'batch_timing'].includes(intent)) {
  lead_score = 'Warm';
}

// Never downgrade existing lead score
const existingScore = item.existing_lead_score;
if (existingScore === 'Hot') {
  lead_score = 'Hot';
} else if (existingScore === 'Warm' && lead_score === 'Cold') {
  lead_score = 'Warm';
}

// Try to extract course name from message
const courseNames = ['python', 'java', 'react', 'node', 'mern', 'web', 'flutter', 'android', 'ios',
  'data science', 'data analytics', 'machine learning', 'ai', 'ui', 'ux', 'graphic design',
  'digital marketing', 'seo', 'laravel', 'php', 'wordpress', 'c++', 'c#', 'bca', 'bsc'];
let detectedCourse = 'our IT courses';
for (const course of courseNames) {
  if (text.includes(course)) {
    detectedCourse = course.charAt(0).toUpperCase() + course.slice(1);
    break;
  }
}

return [{
  json: {
    ...item,
    intent,
    lead_score,
    sla_time,
    detected_course: detectedCourse
  }
}];

const item = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

// Fetch reply templates from CRM
let templates = [];
try {
  const tplResp = await this.helpers.httpRequest({
    method: 'GET',
    url: CRM + '/api/templates',
    headers: headers,
    json: true
  });
  templates = tplResp.data || [];
  if (!Array.isArray(templates)) templates = [templates];
} catch(e) {}

// Find matching template
let replyTemplate = '';
const match = templates.find(t => t.intent === item.intent);
if (match) {
  replyTemplate = match.reply_template || '';
} else {
  // Fallback for general enquiry
  replyTemplate = 'Thanks for reaching out to ExtraBits Academy! We offer 34+ IT courses across web development, AI/ML, mobile development, design, and more. Visit us for a FREE demo class.';
}

// Replace template variables
let replyText = replyTemplate
  .replace(/\{\{course\}\}/g, item.detected_course || 'our IT courses')
  .replace(/\{\{phone\}\}/g, $vars.ACADEMY_PHONE || '')
  .replace(/\{\{address\}\}/g, $vars.ACADEMY_ADDRESS || '');

return [{ json: { ...item, reply_text: replyText } }];

const item = $input.first().json;

// Send reply based on source
try {
  if (item.source === 'whatsapp') {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://graph.facebook.com/v19.0/' + $env.WHATSAPP_PHONE_NUMBER_ID + '/messages',
      headers: { 'Authorization': 'Bearer ' + $env.WHATSAPP_ACCESS_TOKEN, 'Content-Type': 'application/json' },
      body: {
        messaging_product: 'whatsapp',
        to: item.sender_phone,
        type: 'text',
        text: { body: item.reply_text }
      },
      json: true
    });
  } else if (item.source === 'instagram_dm') {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://graph.facebook.com/v19.0/me/messages',
      headers: { 'Authorization': 'Bearer ' + $vars.META_ACCESS_TOKEN, 'Content-Type': 'application/json' },
      body: {
        recipient: { id: item.sender_instagram_user_id },
        message: { text: item.reply_text }
      },
      json: true
    });
  }
  return [{ json: { ...item, _replySent: true } }];
} catch (error) {
  return [{ json: { ...item, _replySent: false, _replyError: error.message } }];
}

const item = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

const newBotCount = (item.bot_reply_count || 0) + 1;
const isNewLead = !item.existing_lead;

// Build lead upsert body
const leadBody = {
  source: item.source,
  student_name: item.sender_name,
  last_message: item.message_text,
  lead_score: item.lead_score,
  follow_up_status: 'pending',
  bot_reply_count: newBotCount
};

// Source-specific fields
if (item.source === 'whatsapp') {
  leadBody.phone = item.sender_phone;
} else {
  leadBody.instagram_user_id = item.sender_instagram_user_id;
}

// First message only stored in 'message' field
if (isNewLead) {
  leadBody.message = item.message_text;
}

// Course interest if detected
if (item.detected_course && item.detected_course !== 'our IT courses') {
  leadBody.course_interest = item.detected_course;
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: CRM + '/api/leads',
    body: leadBody,
    headers: headers,
    json: true
  });
} catch(e) {}

return [{ json: { ...item, bot_reply_count: newBotCount, _leadUpserted: true } }];

const item = $input.first().json;

// Only notify admin for high-intent leads
const highIntent = (item.intent === 'fees_question' || item.intent === 'course_enquiry');

if (!highIntent) {
  return [{ json: { status: 'complete', notified: false } }];
}

const contactInfo = item.source === 'whatsapp'
  ? 'Phone: ' + item.sender_phone
  : 'IG User ID: ' + item.sender_instagram_user_id;

const tgText = '🔥 ' + item.lead_score + ' LEAD: ' + item.sender_name + '\n' +
  'Source: ' + item.source + '\n' +
  'Message: ' + item.message_text + '\n' +
  'Intent: ' + item.intent + '\n' +
  'Follow-up SLA: ' + item.sla_time + '\n' +
  contactInfo + '\n\n' +
  'Reply within target time!';

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
  body: { chat_id: $env.TELEGRAM_CHAT_ID, text: tgText },
  json: true
});

return [{ json: { status: 'complete', notified: true, lead_score: item.lead_score } }];
